import fs from 'fs';
import path from 'path';
import { textOnlyMessage, sendText } from '#helper';
import { downloadMediaMessage } from 'baileys';

/**
 * @param {import('../types/plugin.js').HandlerParams} params
 */
async function handler({ sock, m, jid, text }) {
    if (!textOnlyMessage(m)) return;

    // 1. Cek apakah user me-reply document
    if (m.q && m.q.type === 'documentMessage') {
        try {
            await sock.sendMessage(jid, { react: { text: '⏳', key: m.key } });

            const buffer = await downloadMediaMessage(
                m.q,
                'buffer',
                {},
                { logger: console }
            );

            // Asumsi file document adalah file teks/kode (.txt, .js, .json, dll)
            let content = buffer.toString('utf-8');
            const fileName = m.q.message.documentMessage.fileName || 'document';

            const MAX_LENGTH = 10000;
            let isCut = false;
            if (content.length > MAX_LENGTH) {
                content = content.substring(0, MAX_LENGTH);
                isCut = true;
            }

            let output = `📄 *File Document:* \`${fileName}\`\n\n\`\`\`text\n${content}\n\`\`\``;
            if (isCut) {
                output += '\n\n... _[Teks terlalu panjang, isi dipotong]_ ...';
            }

            await sock.sendMessage(jid, { react: { text: '✅', key: m.key } });
            return await sendText(sock, jid, output, m);

        } catch (err) {
            console.error(err);
            await sock.sendMessage(jid, { react: { text: '❌', key: m.key } });
            return await sendText(sock, jid, `❌ *Gagal membaca dokumen file:*\n${err.message}`, m);
        }
    }

    // 2. Logika membaca isi file server (Fallback jika tidak mereply document)
    if (!text) {
        return await sendText(sock, jid, `❌ *Format Salah*\nFormat 1: \`cat <lokasi_file_di_server>\`\nFormat 2: Reply sebuah file dokumen (.js/.txt) dengan tulisan \`cat\``, m);
    }

    const targetPath = path.resolve(text.trim());

    try {
        if (!fs.existsSync(targetPath)) {
            return await sendText(sock, jid, `❌ *Error:*\nLokasi file server tidak ditemukan:\n\`${targetPath}\``, m);
        }

        const stats = fs.statSync(targetPath);
        if (stats.isDirectory()) {
            return await sendText(sock, jid, `❌ *Error:*\n\`${targetPath}\` adalah sebuah folder server. Gunakan \`ls\` untuk melihat isi folder.`, m);
        }

        let content = fs.readFileSync(targetPath, 'utf-8');

        const MAX_LENGTH = 10000;
        let isCut = false;
        if (content.length > MAX_LENGTH) {
            content = content.substring(0, MAX_LENGTH);
            isCut = true;
        }

        let output = `📄 *File Server:* \`${path.basename(targetPath)}\`\n📍 *Lokasi:* \`${targetPath}\`\n\n\`\`\`javascript\n${content}\n\`\`\``;
        if (isCut) {
            output += '\n\n... _[Teks terlalu panjang, isi dipotong]_ ...';
        }

        await sendText(sock, jid, output, m);

    } catch (err) {
        console.error(err);
        await sendText(sock, jid, `❌ *Gagal membaca file server:*\n${err.message}`, m);
    }
}

