import { reply } from '../../core/helper/baileys/baileys-generic.js'
import { isJidGroup } from 'baileys'
import { db } from '../../core/database/database.js'
import { createCanvas, loadImage, GlobalFonts } from '@napi-rs/canvas'
import fs from 'node:fs'
import { Readable, Stream } from 'node:stream'
import path from 'node:path'
import { allPath } from '../../core/all-path.js'


const stmt = db.prepare(`
    WITH params(day, chat_id) AS (
  SELECT :num, :chatId -- Ganti 17 dengan tanggal, 2 dengan chat_id yang dicari
),
day_start AS (
  SELECT
    strftime('%s','now','+8 hours','start of month','+'||(day-1)||' days','-8 hours') AS start_utc,
    strftime('%s','now','+8 hours','start of month','+'||day||' days','-8 hours') AS end_utc,
    chat_id
  FROM params
),
-- Menghasilkan angka 0 sampai 23 untuk baris jam
hours(hour) AS (
  SELECT 0
  UNION ALL
  SELECT hour + 1 FROM hours WHERE hour < 23
),
-- Ambil data pesan yang relevan saja dalam satu tarikan
filtered_messages AS (
  SELECT 
    CAST((m.timestamp - d.start_utc) / 3600 AS INT) AS msg_hour
  FROM messages m
  JOIN day_start d ON m.chat_id = d.chat_id
  WHERE m.timestamp >= d.start_utc 
    AND m.timestamp < d.end_utc
)
-- Gabungkan jam dengan data pesan
SELECT
  h.hour,
  COUNT(fm.msg_hour) AS total_messages
FROM hours h
LEFT JOIN filtered_messages fm ON h.hour = fm.msg_hour
GROUP BY h.hour
ORDER BY h.hour;
`)


/** @param {import('../../core/type/plugin.js').HandlerParams} */
async function plugin({ sock, jid, text, m, q, prefix, command, other }) {
  let awo = (rows, gcName) => {
    const labels = []
    const data = []
    let peakHour = 0
    let peakMessage = 0
    let totalMessage = 0
    let messagePerHour = 0
    const api = 'https://quickchart.io/chart/render/zm-7f4e3186-7edd-4fa4-8d2b-51b747ac7737'
    for (let i = 0; i < rows.length; i++) {
      const row = rows[i]
      labels.push(row.hour)
      data.push(row.total_messages)
      if (peakMessage < row.total_messages) {
        peakHour = row.hour
        peakMessage = row.total_messages
      }
      totalMessage += row.total_messages
    }
    messagePerHour = Math.round(totalMessage / 24)

    //const url = api + '?title=' + decodeURIComponent(gcName) + '&labels=' + labels.join(',') + '&data1=' + data.join(',')
    const url = api + '?title=' + "chart" + '&labels=' + labels.join(',') + '&data1=' + data.join(',')
    return { url, peakHour, peakMessage, totalMessage, messagePerHour }

  }


  if (!isJidGroup(jid)) return await reply(sock, m, 'hanya bisa di grup aja ya sayang.')

  if (!/^\d+$/.test(text)) return reply(sock, m, 'masukin tanggal (angka aja)')




  const result = stmt.all({ num: text, chatId: m.chat.id })
  if (!result.length) return await reply('no data')
  const hm = awo(result, m.chat.chatName + ', tanggal ' + text)
  console.log(hm)


  const gm = await sock.ws.config.cachedGroupMetadata(jid)

  const adminsName = gm.participants.filter(p => p.admin).map(p => {
    const c = other.storeContact.contactsMap.get(p.id)
    let pushName = c?.pushName || '(unknown admin)'
    return pushName.normalize('NFKC')
  }).sort()



  const fontPath = path.join(allPath.user, 'canvas', 'font')
  GlobalFonts.registerFromPath(path.join(fontPath, 'SFUIText-Regular.otf'), 'apple')
  GlobalFonts.registerFromPath(path.join(fontPath, 'NotoColorEmoji-Regular.ttf'), 'apple-color-emoji')

  const width = 2000
  const height = 600 + 1000 + 700

  const canvas = createCanvas(width, height)
  const ctx = canvas.getContext('2d')

  // bekgron
  ctx.fillStyle = '#f5f5f5'
  ctx.fillRect(0, 0, width, height)

  // pp grup
  const url1 = await sock.profilePictureUrl(jid, 'image')
  const image = await loadImage(url1)
  ctx.drawImage(image, 100, 100, 400, 400)

  // set font
  const xbase1 = 650
  const ybase1 = 205
  const yincrement = 60
  ctx.fillStyle = '#474747'
  ctx.font = 'bold 60px Arial, apple-color-emoji'
  ctx.fillText(m.chat.chatName.normalize("NFKC"), xbase1, ybase1)
  ctx.font = 'bold 40px Arial'
  ctx.fillText(gm.participants.length + ' MEMBERS', xbase1, ybase1 + 1 * yincrement)
  ctx.font = 'bold 40px Arial'
  ctx.fillText(gm.participants.filter(m => m.admin).length + ' ADMINS', xbase1, ybase1 + 2 * yincrement)
  ctx.font = 'bold 40px Arial'
  ctx.fillText(hm.totalMessage + ' TOTAL MESSAGES SENT', xbase1, ybase1 + 4 * yincrement)

  // CONTENT
  const urlDiagram = hm.url
  const image2 = await loadImage(urlDiagram)
  ctx.drawImage(image2, 0, 600)






  //footer
  ctx.fillStyle = '#181818'
  ctx.fillRect(0, 600 + 1000, width, 700)
  ctx.fillStyle = '#474747'
  ctx.font = 'bold 40px Arial'
  const angel = 'made by angelina bot'
  const lulu = ctx.measureText(angel)
  ctx.fillText(angel, (width - lulu.width) / 2, 2250)
  ctx.fillStyle = '#d3d3d3'
  const awoa = 'group managed by'
  const lala = ctx.measureText(awoa)
  ctx.fillText(awoa, (width - lala.width) / 2, 1700)

  // CONFIGURATION
  const maxNameInRow = 4
  const verticalGap = 80
  const paddingTop = 600 + 1000 + 200

  const horizontalGap = width / maxNameInRow

  // admin name

  /**
   * 
   * @param {import('@napi-rs/canvas').SKRSContext2D} ctx 
   * @param {number} x 
   * @param {number} y 
   * @param {string} text 
   */
  const writeText = (ctx, x, y, text, horizontalGap) => {
    ctx.fillStyle = '#d3d3d3'
    ctx.font = '34px Arial, apple-color-emoji, apple'
    const metric = ctx.measureText(text)
    console.log(metric.width)
    ctx.fillText(text, (horizontalGap - metric.width) / 2 + x, y)
  }

  const admins = adminsName

  for (let i = 0; i < admins.length; i++) {
    const x = (i % maxNameInRow) * horizontalGap
    const y = (Math.floor(i / maxNameInRow) * verticalGap) + paddingTop
    writeText(ctx, x, y, admins[i], horizontalGap)
  }



  const canvasStream = canvas.encodeStream('webp')





  return sock.sendMessage(jid, {
    image: { stream: Readable.fromWeb(canvasStream) },
    caption: `group report\ntanggal ${text}\npeak di jam ${hm.peakHour} dengan ${hm.peakMessage} pesan.\n\ntotal pesan: ${hm.totalMessage}. rata rata: ${hm.messagePerHour} pesan/jam.\n\n> report by angelina bot`
  })


  // return sock.sendMessage(jid, {
  //   image: { url: hm.url  },
  //   caption: `group report\ntanggal ${text}\npeak di jam ${hm.peakHour} dengan ${hm.peakMessage} pesan.\n\ntotal pesan: ${hm.totalMessage}. rata rata: ${hm.messagePerHour} pesan/jam.\n\n> report by angelina bot`
  // })




}

